definition.script:
pipeline{
    agent any
    stages {
        stage('Initialize') {
            steps {
                echo 'Initializing Autonomous DevOps Platform'
                echo 'Checking Environment Capability'
            }
        }
        stage('System Check') {
            steps {
                sh 'uname -a'
                echo 'Architechture: Apple Silicon M4'
            }
        }
    }
}
